message.content:
@startuml
' Define custom stereotype for classes to match the green 'C' icon in original
skinparam classStereotypeStyle rectangle #90EE90 black

class Buchung {
    hotelZimmer: Hotelzimmer
    gast: Gast
    anreiseDatum: LocalDate
    abreiseDatum: LocalDate
}

class LeistungspaketBuchung {
    leistungspaket: Leistungspaket
    buchung: Buchung
    anzahl: int
}

class LuxuspaketPaket {
    bezeichnung: String
    leistungspaket: Leistungspaket
}

class Mitarbeiter {
    svnr: String
    name: String
    adresse: String
}

class Betreuer {
    mitarbeiter: Mitarbeiter
    fach: String
}

class Kategorie {
    id: int
    bezeichnung: String
}

class HotelzimmerKategorie {
    hotelZimmer: Hotelzimmer
    kategorie: Kategorie
}

class HotelzimmerMitarbeiter {
    hotelZimmer: HotelzimmerMitHotelzimmer
    mitarbeiter: MitHotelzimmerMitarbeiter
    datum: LocalDate
}

note right of "ein Luxuspaketsystem hat mehrere Einträge mit der gleichen Bezeichnung" : ein Luxuspaketsystem\nhat mehrere Einträge \nmit der gleichen Bezeichnung

Booking --* Guest : 1..* 
Guest *-- Address 

LuxusPackage o-- LuxuryServicePackaging  
LeisureActivity <|-- LeisureBookings  

StaffMember --> Supervisor   
Supervisor ..> StaffAssignment   

RoomCategory -|-> RoomType    
AccommodationUnit ||-o{ BookingRecord    

@enduml
